postCreateCommand:
python3 -m venv .venv && . .venv/bin/activate && pip install jupyter notebook jupyterlab ipykernel && npm install -g ijavascript && mkdir -p ~/.local/share/jupyter/kernels/javascript && printf '{
  "argv": [
    "node",
    "/usr/local/share/npm-global/lib/node_modules/ijavascript/lib/kernel.js",
    "{connection_file}"
  ],
  "display_name": "JavaScript (Node.js)",
  "language": "javascript"
}' > ~/.local/share/jupyter/kernels/javascript/kernel.json
